INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6fcd6d8e-6259-459d-83a3-de96c81550f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Feature Folders: Colocation Over Convention$escape$,
  $escape$Grouping files by type (`components/`, `hooks/`, `utils/`) breaks down fast as apps grow — you end up chasing imports across the tree for a single feature. Feature-based folders flip this: every file a feature needs lives together. A `UserProfile` feature owns its component, hook, types, and tests in one directory. Colocation means the `useUserProfile` hook is only ever imported by `UserProfile` — it's never accidentally shared.

Barrel exports (`index.ts`) are the public API of each feature. Only what's explicitly re-exported is considered stable. Internal helpers stay unexported, enforcing a clear boundary. This makes refactoring safe: rename a file inside `features/user-profile/` and nothing outside breaks as long as the barrel contract holds.

Avoid deep barrel chains (barrel importing barrels) — they cause Webpack/Turbopack to pull in entire feature trees during tree-shaking analysis, inflating cold-start times. Keep barrels shallow: one level per feature boundary.$escape$,
  $escape$// features/user-profile/index.ts  ← public API
export { UserProfile } from './UserProfile';
export type { UserProfileProps } from './UserProfile.types';
// useUserProfile is NOT exported — internal only

// features/user-profile/UserProfile.tsx
import { useUserProfile } from './useUserProfile';   // colocated
import { Avatar } from '@/components/ui/Avatar';      // shared UI

export function UserProfile({ userId }: UserProfileProps) {
  const { data, isLoading } = useUserProfile(userId);
  return isLoading ? <Skeleton /> : <Avatar src={data.avatarUrl} />;
}$escape$,
  $escape$typescript$escape$,
