INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '568c14a4-e120-4ff4-affe-3430035ff95e',
  '00000000-0000-0000-0000-000000000001',
  $escape$React State Placement: Local, Lifted, Context, or External Store?$escape$,
  $escape$Pick the narrowest scope that works. useState stays local when only one component needs the value — form inputs, toggle states, hover flags. Lift state to the nearest common ancestor when siblings need to share it; pass it down as props. Don't reach for Context to avoid prop drilling unless the data is truly global (theme, auth, locale) — Context re-renders every consumer on every change, so it's expensive for high-frequency updates. For server cache, async state, or cross-cutting UI state that changes often (cart, filters, optimistic updates), use an external store: Zustand for minimal boilerplate, Redux Toolkit when you need DevTools and middleware, Jotai or Recoil for fine-grained atom-level subscriptions that skip full-tree renders. The signal to upgrade: you're passing props more than two levels deep, or you're adding useEffect to sync two useState calls. That's the smell — not the proof — that you need to lift or externalize. Co-locate state with the component that owns it; only promote when forced.$escape$,
  $escape$// Zustand: fine-grained external store
import { create } from 'zustand';

interface FilterStore {
  query: string;
  setQuery: (q: string) => void;
}

const useFilterStore = create<FilterStore>((set) => ({
  query: '',
  setQuery: (q) => set({ query: q }),
}));

// Only re-renders components that call useFilterStore
function SearchBar() {
  const { query, setQuery } = useFilterStore();
  return <input value={query} onChange={(e) => setQuery(e.target.value)} />;
}$escape$,
  $escape$typescript$escape$,
