INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3d098a5e-0803-4711-ad90-c2f81ac16d99',
  '00000000-0000-0000-0000-000000000001',
  $escape$React useMemo & useCallback: Stop Memoizing Everything$escape$,
  $escape$Memoization in React isn't free — it has CPU cost for the comparison and memory cost for caching the previous value. The question isn't 'can I memoize this?' but 'is the recalculation more expensive than the comparison?'

useMemo is worth it for referentially stable values passed to memo()-wrapped children, or for genuinely expensive computations (sorting large arrays, heavy transforms). Wrapping a simple string concat or arithmetic in useMemo adds overhead, not removes it.

useCallback only pays off when the function is a dependency in another hook (useEffect, useMemo) or is passed as a prop to a memoized child. A bare event handler on a div doesn't benefit — React's reconciler doesn't bail out based on function identity for host elements.

The real win: profile first with React DevTools Profiler. Look for components with high render counts and expensive subtrees. Memoize at the boundary — the component receiving the prop — using React.memo(), then stabilize the prop with useMemo/useCallback upstream. Memoizing without React.memo() on the child is wasted work.$escape$,
  $escape$// Only worth memoizing when child is wrapped in React.memo()
const Child = React.memo(({ onAction, items }: Props) => (
  <ul>{items.map(i => <li key={i.id} onClick={() => onAction(i.id)}>{i.name}</li>)}</ul>
));

function Parent({ rawItems }: { rawItems: Item[] }) {
  // useMemo: stable reference across renders for expensive sort
  const sorted = useMemo(() => [...rawItems].sort((a, b) => a.name.localeCompare(b.name)), [rawItems]);

  // useCallback: stable reference so Child doesn't re-render
  const handleAction = useCallback((id: string) => {
    console.log('action', id);
  }, []); // no deps — pure side effect

  return <Child onAction={handleAction} items={sorted} />;
}$escape$,
  $escape$typescript$escape$,
