INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '963b2b01-334c-49dc-94c5-720f63eae6cf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Server State vs Client State in React — Stop Managing Both the Same Way$escape$,
  $escape$Most React apps over-use useState for data that doesn't belong there. Server state (fetched from an API) is fundamentally different from client state (UI flags, form inputs): it's async, can go stale, is shared across components, and needs cache invalidation. Stuffing it into useState forces you to manually handle loading, error, and refetch logic everywhere.

TanStack Query treats server state as a first-class citizen. useQuery caches by queryKey, deduplicates in-flight requests, and revalidates on window focus automatically. useMutation pairs with queryClient.invalidateQueries() to keep the cache fresh after writes — no manual setState juggling.

Keep useState strictly for ephemeral UI state: modal open/closed, selected tab, optimistic toggles. If the data lives on a server, it belongs in TanStack Query. This boundary also unlocks devtools visibility into cache state, retries, and background refetches — invaluable for debugging race conditions that useState-based fetching silently swallows.$escape$,
  $escape$// ✅ Server state → TanStack Query
const { data: user, isLoading } = useQuery({
  queryKey: ['user', userId],
  queryFn: () => fetch(`/api/users/${userId}`).then(r => r.json()),
  staleTime: 1000 * 60 * 5, // 5 min cache
});

const { mutate: updateUser } = useMutation({
  mutationFn: (payload) => fetch(`/api/users/${userId}`, { method: 'PATCH', body: JSON.stringify(payload) }),
  onSuccess: () => queryClient.invalidateQueries({ queryKey: ['user', userId] }),
});

// ✅ Client state → useState
const [isEditing, setIsEditing] = useState(false);$escape$,
  $escape$typescript$escape$,
