INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '46b59a05-af4d-4a1f-84e3-6e7d2a0a3de5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Stop Writing Controlled Inputs — React Hook Form + Zod Is the Pattern$escape$,
  $escape$Controlled inputs (`useState` per field) re-render on every keystroke and bloat component state. Uncontrolled inputs (ref-based) avoid re-renders but lose validation ergonomics. React Hook Form threads the needle: it registers inputs via refs under the hood, so your component stays uncontrolled and fast, while `useForm` gives you a single `errors` object and a type-safe `handleSubmit`.

Pair it with Zod via `@hookform/resolvers/zod` and you get schema-driven validation that colocates your types with your rules. Define a `z.object()` schema, infer the TypeScript type from it with `z.infer`, and pass the resolver to `useForm`. Now your form input types, validation rules, and submit handler payload are all derived from one source of truth — no manual type assertions, no duplicated error messages.$escape$,
  $escape$import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const schema = z.object({
  email: z.string().email(),
  age: z.number({ coerce: true }).min(18),
});

type FormData = z.infer<typeof schema>;

export function SignupForm() {
  const { register, handleSubmit, formState: { errors } } = useForm<FormData>({
    resolver: zodResolver(schema),
  });

  return (
    <form onSubmit={handleSubmit((data) => console.log(data))}>
      <input {...register('email')} />
      {errors.email && <span>{errors.email.message}</span>}
      <input type="number" {...register('age')} />
      {errors.age && <span>{errors.age.message}</span>}
      <button type="submit">Submit</button>
    </form>
  );
}$escape$,
  $escape$typescript$escape$,
