INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3303c5aa-01cd-4089-86b6-c911b6a2ec17',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Discriminated Unions: Type-Safe Component Variants Without `any`$escape$,
  $escape$Typing React props with `any` silently breaks refactoring — the compiler can't catch mismatched variant combinations. Discriminated unions fix this by adding a literal `type` field that narrows the type inside each branch. When you render a `<Button variant="primary" />`, TypeScript now knows exactly which props are valid for that variant — no casting, no guessing.

The pattern shines when variants need mutually exclusive props. A `LinkButton` needs `href`, a plain `Button` needs `onClick` — putting both optional on one interface lets invalid combinations compile silently. With a discriminated union, the compiler enforces the contract at the call site.

Use `React.ComponentPropsWithoutRef` to spread native element props safely without losing the discrimination. Avoid intersecting with `{ [key: string]: any }` — it defeats the entire model. If a prop legitimately accepts multiple shapes, reach for generics or explicit overloads instead. The goal is making illegal states unrepresentable inside JSX, not just at runtime.$escape$,
  $escape$type ButtonProps =
  | ({ variant: 'primary'; onClick: () => void } & React.ComponentPropsWithoutRef<'button'>)
  | ({ variant: 'link'; href: string } & React.ComponentPropsWithoutRef<'a'>);

function Button(props: ButtonProps) {
  if (props.variant === 'link') {
    const { variant, href, ...rest } = props;
    return <a href={href} {...rest} />;
  }
  const { variant, onClick, ...rest } = props;
  return <button onClick={onClick} {...rest} />;
}

// ✅ Valid
<Button variant="link" href="/docs" />
// ❌ Type error: 'href' does not exist on primary variant
<Button variant="primary" href="/docs" />$escape$,
  $escape$typescript$escape$,
