INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5e7d65f5-d7e0-499d-b4c1-8bcae1c0d1f9',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Testing Library: Query by Role, Not by Class$escape$,
  $escape$Most React test bugs come from testing implementation details — querying by class names, checking internal state, or asserting on component structure. When you refactor, those tests break even though the UI still works correctly. Testing Library's philosophy flips this: query the DOM the way a user or assistive technology would. Use `getByRole('button', { name: /submit/i })` instead of `getByTestId('submit-btn')`. Use `getByLabelText` for inputs instead of `querySelector`. Fire events with `userEvent.click()` instead of manually invoking handlers. Assert on what the user sees — visible text, ARIA roles, disabled states — not on React's internal tree. This makes your tests resilient to refactors: you can swap a `<div onClick>` for a `<button>`, rename CSS classes, or lift state up, and the tests stay green. The rule of thumb: if your test would still pass after completely rewriting the component internals, it's testing the right thing.$escape$,
  $escape$// Bad: tests implementation detail
const btn = container.querySelector('.submit-btn');
expect(component.state('loading')).toBe(true);

// Good: tests user-visible behaviour
const btn = screen.getByRole('button', { name: /submit/i });
await userEvent.click(btn);

expect(screen.getByText(/loading/i)).toBeInTheDocument();
expect(btn).toBeDisabled();

// Good: form input via label association
const emailInput = screen.getByLabelText(/email address/i);
await userEvent.type(emailInput, 'dev@example.com');$escape$,
  $escape$javascript$escape$,
