INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '24b6d453-7219-4884-aafa-111b74a84768',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Security Traps: XSS, Token Storage, and Sanitization$escape$,
  $escape$React's JSX auto-escapes strings, but three patterns break that guarantee. First, `dangerouslySetInnerHTML` bypasses React's escaping entirely — never pass unsanitized user content to it. Use DOMPurify's `sanitize()` before setting innerHTML, or better yet, render plain text via JSX. Second, storing JWTs in `localStorage` exposes them to any XSS payload on your domain — use `httpOnly` cookies issued by your backend instead; they're inaccessible to JavaScript. Third, controlled inputs don't sanitize — they just bind values. If you're feeding user input into a `dangerouslySetInnerHTML`, a query string, or an `eval`-adjacent API, sanitize explicitly. For rich text, DOMPurify is the standard; configure it with a strict `ALLOWED_TAGS` allowlist rather than relying on defaults. React's security model assumes you own the content pipeline — the moment user-generated strings touch raw DOM APIs or your token store, that assumption breaks. Treat every `dangerouslySetInnerHTML` usage as a code smell requiring a peer review sign-off.$escape$,
  $escape$import DOMPurify from 'dompurify';

const ALLOWED = { ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a'], ALLOWED_ATTR: ['href'] };

function SafeRichText({ html }: { html: string }) {
  const clean = DOMPurify.sanitize(html, ALLOWED);
  // Only use dangerouslySetInnerHTML after explicit sanitization
  return <div dangerouslySetInnerHTML={{ __html: clean }} />;
}

// ❌ Never do this — raw user input directly into the DOM
// <div dangerouslySetInnerHTML={{ __html: userInput }} />

// ❌ Don't store tokens in localStorage
// localStorage.setItem('token', jwt);
// ✅ Let backend set httpOnly cookie; fetch with credentials: 'include'$escape$,
  $escape$typescript$escape$,
