INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e23e14b6-2ebe-479e-9675-b23f35860a09',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Code Quality: eslint-plugin-react-hooks, Naming Rules, and the 50-Line Limit$escape$,
  $escape$The `eslint-plugin-react-hooks` package enforces two non-negotiable rules: `rules-of-hooks` (no conditional hook calls) and `exhaustive-deps` (no missing dependencies in `useEffect`, `useMemo`, `useCallback`). Ignoring `exhaustive-deps` warnings is how stale closure bugs are born — the linter is almost always right.

Naming matters more in React than in most frameworks. Custom hooks must start with `use` — this isn't stylistic, it's what enables the linter to track hook call order. Components must be PascalCase; lowercase components are treated as DOM elements by JSX. Handler props should be `onX`, the handlers themselves `handleX`.

The 50-line rule applies at the component level: if your JSX plus logic exceeds ~50 lines, you have an implicit second responsibility. Extract it. A `UserCard` that fetches, formats, and renders is three components pretending to be one. Split into a data hook (`useUserCard`), a presenter (`UserCardView`), and a thin connector. Each becomes independently testable and the linter has less surface to misread.$escape$,
  $escape$// .eslintrc.js
module.exports = {
  plugins: ['react-hooks'],
  rules: {
    'react-hooks/rules-of-hooks': 'error',
    'react-hooks/exhaustive-deps': 'warn',
  },
};

// Good: hook naming + split responsibility
function useUserCard(userId: string) {
  const [user, setUser] = React.useState<User | null>(null);
  React.useEffect(() => {
    fetchUser(userId).then(setUser);
  }, [userId]); // exhaustive-deps satisfied
  return user;
}

function UserCardView({ user }: { user: User }) {
  return <div className="card">{user.name}</div>;
}$escape$,
  $escape$typescript$escape$,
