INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02d9f37b-59bd-4fbc-9b66-a300a720568f',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Accessibility: Semantic HTML First, ARIA as a Last Resort$escape$,
  $escape$Most React accessibility bugs stem from using `<div onClick>` where a `<button>` belongs. Semantic HTML gives you keyboard support, focus management, and screen reader announcements for free — no extra code. Reach for ARIA only when native elements genuinely can't model your UI.

For focus management, use `useRef` + `.focus()` after state transitions — e.g., move focus to a modal heading when it opens, and back to the trigger when it closes. React 19's `<dialog>` support makes this even cleaner with native `showModal()` semantics.

When you do need ARIA, be surgical: `aria-live="polite"` for async status updates, `aria-expanded` on a toggle button that controls a collapsible, `role="status"` on toast containers. Never add `aria-label` to an element that already has visible text — it creates a mismatch for voice control users.

Lint-gate this with `eslint-plugin-jsx-a11y`. It catches missing `alt`, implicit roles, and invalid ARIA combos at author time, before they ship.$escape$,
  $escape$// Focus management: return focus to trigger when modal closes
function Modal({ isOpen, onClose, triggerRef, children }) {
  const headingRef = useRef(null);

  useEffect(() => {
    if (isOpen) {
      headingRef.current?.focus();
    } else {
      triggerRef.current?.focus(); // restore focus on close
    }
  }, [isOpen]);

  if (!isOpen) return null;
  return (
    <dialog open aria-modal="true">
      <h2 ref={headingRef} tabIndex={-1}>{children}</h2>
      <button onClick={onClose}>Close</button>
    </dialog>
  );
}$escape$,
  $escape$javascript$escape$,
