INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fa820dcf-1eb0-4d08-9e49-3a6086cba279',
  '00000000-0000-0000-0000-000000000001',
  $escape$React i18n: react-i18next + Intl API, No Hardcoded Strings$escape$,
  $escape$Hardcoding strings in JSX is an i18n anti-pattern that creates refactor debt at scale. Use react-i18next's `useTranslation` hook to externalize all user-facing text into JSON namespaces. Wrap your app in `I18nextProvider` and call `i18n.changeLanguage('fr')` to hot-swap locales without a remount.

For dates and numbers, skip third-party libraries — the native `Intl` API handles locale-aware formatting directly in React. Use `useMemo` to avoid recreating `Intl.DateTimeFormat` and `Intl.NumberFormat` instances on every render.

Key patterns: use `Trans` component for JSX-interpolated strings (e.g., links inside translations), never template-literal concatenate translated substrings, and always namespace translations (`t('common:save')`) to enable lazy-loading via `i18next-http-backend`. Co-locate locale JSON files per feature slice, not one monolithic `en.json`. For pluralization, lean on i18next's built-in plural suffixes (`_one`, `_other`) rather than manual ternaries in JSX.$escape$,
  $escape$import { useTranslation } from 'react-i18next';

const OrderSummary = ({ date, total, count }: Props) => {
  const { t, i18n } = useTranslation('orders');
  const locale = i18n.language;

  const formattedDate = useMemo(
    () => new Intl.DateTimeFormat(locale, { dateStyle: 'medium' }).format(date),
    [date, locale]
  );
  const formattedTotal = new Intl.NumberFormat(locale, { style: 'currency', currency: 'USD' }).format(total);

  return (
    <p>{t('summary', { count, date: formattedDate, total: formattedTotal })}</p>
  );
};$escape$,
