INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '890a0bcd-1d28-4de0-b39b-004de8df672c',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Memory Leaks — useEffect Cleanup, AbortController, and removeEventListener$escape$,
  $escape$Every useEffect that sets state, subscribes to events, or fetches data is a leak waiting to happen if you skip the cleanup function. When a component unmounts before an async fetch resolves, calling setState on the dead component triggers React's "Can't perform a state update on an unmounted component" warning — and wastes memory.

Use AbortController to cancel in-flight fetch requests. Pass signal to fetch(), and in the cleanup return, call controller.abort(). React will call your cleanup on unmount and before re-running the effect on dependency changes.

For DOM event listeners added inside useEffect, always mirror every addEventListener with a removeEventListener in the cleanup — same reference, same options object shape. Arrow functions inline will never match, so extract the handler to a variable first.

Custom hooks that wrap subscriptions (WebSocket, ResizeObserver, IntersectionObserver) must return cleanup too — consumers shouldn't need to know the internals. Returning the unsubscribe/disconnect call from useEffect is the contract React expects.$escape$,
  $escape$useEffect(() => {
  const controller = new AbortController();

  async function fetchData() {
    try {
      const res = await fetch('/api/data', { signal: controller.signal });
      const json = await res.json();
      setData(json);
    } catch (err) {
      if (err.name !== 'AbortError') setError(err);
    }
  }

  const handleResize = () => setWidth(window.innerWidth);
  window.addEventListener('resize', handleResize);
  fetchData();

  return () => {
    controller.abort();
    window.removeEventListener('resize', handleResize);
  };
}, []);$escape$,
  $escape$javascript$escape$,
