INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ecede413-bad3-4784-8f78-4f7085114070',
  '00000000-0000-0000-0000-000000000001',
  $escape$React WebSockets — Singleton Connection, Reconnect, and Optimistic UI$escape$,
  $escape$Mounting a WebSocket inside useEffect per-component creates redundant connections. Instead, create a singleton outside React and share it via context. Use a ref to hold the socket instance so re-renders don't trigger reconnects. For reconnection, track readyState in state and schedule exponential-backoff retries with setTimeout — clear the timer in the cleanup function to avoid stale closures. For optimistic UI on send, append the message to local state immediately before calling socket.send(). Assign a clientId to each pending message. On server ack, replace the pending entry using that id; on error, mark it failed or roll back. Avoid putting the raw WebSocket in useState — it's not serializable and triggers unnecessary re-renders. Instead, keep it in a ref and only put derived UI state (messages, status) in useState. This pattern gives you a stable connection, resilient reconnect loop, and instant UI feedback without waiting for the round-trip.$escape$,
  $escape$const useSocket = (url: string) => {
  const socketRef = useRef<WebSocket | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);

  useEffect(() => {
    const connect = () => {
      const ws = new WebSocket(url);
      socketRef.current = ws;
      ws.onmessage = (e) => {
        const ack = JSON.parse(e.data);
        setMessages(prev =>
          prev.map(m => m.clientId === ack.clientId ? { ...m, confirmed: true } : m)
        );
      };
      ws.onclose = () => setTimeout(connect, 2000);
    };
    connect();
    return () => socketRef.current?.close();
  }, [url]);

  const send = (text: string) => {
    const msg = { clientId: crypto.randomUUID(), text, confirmed: false };
    setMessages(prev => [...prev, msg]);
    socketRef.current?.send(JSON.stringify(msg));
  };

  return { messages, send };
};$escape$,
