INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6d1331f6-eccc-4e09-aa4e-116047ed3f18',
  '00000000-0000-0000-0000-000000000001',
  $escape$Validate React Env Vars at Startup with Zod — Catch Misconfigs Before They Hit Users$escape$,
  $escape$Hardcoding API URLs or keys in React components is a silent killer — it breaks across environments and leaks secrets into bundles. Vite exposes only `VITE_` prefixed vars to the client; Create React App uses `REACT_APP_`. Either way, a missing var silently becomes `undefined`, causing runtime failures deep in your app.

The fix: validate your env contract at module load time using Zod. Create a `src/env.ts` file that parses `import.meta.env` (Vite) or `process.env` (CRA) against a schema. If validation fails, throw immediately — crashing at startup is infinitely better than a cryptic fetch error in production.

This gives you type-safe env access throughout the app (`env.VITE_API_URL` instead of raw strings), IDE autocomplete, and a single source of truth. Pair it with `.env.example` committed to git and `.env.local` gitignored. For CI, set vars as pipeline secrets — never commit real values. This pattern scales cleanly from local dev to staging to prod without a single URL change in component code.$escape$,
  $escape$// src/env.ts
import { z } from 'zod';

const envSchema = z.object({
  VITE_API_URL: z.string().url(),
  VITE_CLERK_PUBLISHABLE_KEY: z.string().min(1),
  VITE_FEATURE_FLAGS: z.string().optional(),
});

const parsed = envSchema.safeParse(import.meta.env);

if (!parsed.success) {
  console.error('Invalid env config:', parsed.error.flatten().fieldErrors);
  throw new Error('App startup aborted: missing or invalid environment variables.');
}

export const env = parsed.data;$escape$,
  $escape$typescript$escape$,
