INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a3d9f4f3-a1ff-4ae1-8695-287bedd18536',
  '00000000-0000-0000-0000-000000000001',
  $escape$React API Layer — One Axios Instance, Zero Raw Fetches in Components$escape$,
  $escape$Scattering `fetch()` calls across components creates silent auth failures, inconsistent error handling, and retry logic duplicated everywhere. The fix: a single Axios instance exported from `lib/api.ts`, configured once with interceptors.

Attach a request interceptor to inject the Bearer token from your auth store (Zustand, Context, or Clerk's `getToken`). Attach a response interceptor to handle 401s — clear the session and redirect — and to normalize error shapes before they bubble to components. For retries, `axios-retry` plugs directly into the instance with exponential backoff.

Components never touch Axios directly. They call typed service functions (`getUser(id)`, `postComment(payload)`) that wrap the instance. React Query or SWR then wraps those service functions — giving you caching, deduplication, and loading states for free.

This boundary keeps components dumb about transport. Swapping Axios for `ky` or adding an auth provider change? One file changes. Token refresh logic lives in the interceptor, not scattered across `useEffect` hooks.$escape$,
  $escape$// lib/api.ts
import axios from 'axios';
import { getAuthToken } from '@/lib/auth';

export const api = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_URL,
  timeout: 10_000,
});

api.interceptors.request.use(async (config) => {
  const token = await getAuthToken();
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) window.location.href = '/login';
    return Promise.reject(err);
  }
);

// services/user.ts
export const getUser = (id: string) =>
  api.get<User>(`/users/${id}`).then((r) => r.data);$escape$,
  $escape$typescript$escape$,
