INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c3530ba6-b4aa-47e6-8a98-39f6d0aca1ca',
  '00000000-0000-0000-0000-000000000001',
  $escape$React Animation: CSS for States, Framer Motion for Sequences, Always Respect prefers-reduced-motion$escape$,
  $escape$Reach for CSS transitions first — they're zero-bundle-cost and handle 80% of UI state changes (hover, focus, open/closed). Apply them via className toggling or inline style, letting the GPU handle interpolation. Framer Motion earns its 43 kB when you need orchestrated sequences, layout animations, or shared-element transitions that CSS can't express cleanly. Use its `motion` components and `AnimatePresence` for mount/unmount choreography. The non-negotiable: always honour `prefers-reduced-motion`. In CSS use the `@media (prefers-reduced-motion: reduce)` block to zero out transitions. In Framer Motion, read `useReducedMotion()` and swap animated variants for instant ones. Wire this once in a top-level hook and pass a `shouldAnimate` flag via context — every component benefits automatically. Never gate the feature itself, only the motion: the UI must still transition between states, just without decorative movement.$escape$,
  $escape$import { motion, useReducedMotion } from 'framer-motion';

const variants = {
  visible: { opacity: 1, y: 0 },
  hidden:  { opacity: 0, y: 12 },
};

export function FadeInCard({ children }: { children: React.ReactNode }) {
  const reduce = useReducedMotion();

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={reduce ? {} : variants}
      transition={{ duration: 0.25, ease: 'easeOut' }}
    >
      {children}
    </motion.div>
  );
}$escape$,
  $escape$typescript$escape$,
