INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd4fb2363-3324-4a7b-8c6d-2ec8d5883cf0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Global UI Patterns — Toast, Modals, and Confirm Dialogs as React Hooks$escape$,
  $escape$Scattering toast calls and modal state across components is a maintenance trap. The cleaner pattern: mount a single <ToastProvider> and <ModalProvider> at your app root, backed by a React context holding a queue or stack. Expose imperative hooks — useToast(), useModal(), useConfirm() — so any component can trigger UI without prop-drilling or lifting state.

useConfirm() is the highest-leverage example. Instead of rendering a <ConfirmDialog open={...}> in every feature component, you call await confirm('Delete this byte?') and get back a boolean. Internally, the hook resolves a Promise when the user clicks OK or Cancel — same pattern as window.confirm(), but fully styled.

This keeps your feature components free of UI orchestration logic. The modal stack in context handles z-index layering, focus trapping, and ESC key dismissal centrally. Pair it with Radix UI's Dialog primitive and you get accessible stacking out of the box. One root, one source of truth, zero modal state scattered across the tree.$escape$,
  $escape$// useConfirm hook backed by ModalContext
function useConfirm() {
  const { openModal, closeModal } = useModalContext();

  return (message: string): Promise<boolean> =>
    new Promise((resolve) => {
      openModal(
        <ConfirmDialog
          message={message}
          onConfirm={() => { resolve(true); closeModal(); }}
          onCancel={() => { resolve(false); closeModal(); }}
        />
      );
    });
}

// Usage anywhere in the tree
const confirm = useConfirm();
if (await confirm('Delete this byte?')) deleteItem(id);$escape$,
  $escape$typescript$escape$,
